nta.declaration:
// Global declarations

// --- Functions converted from C# methods ---

int GetBalance(int deposits, int withdrawals) {
    int balance;
    balance = deposits - withdrawals;
    if (balance < 0) {
        balance = 0;
    }
    return balance;
}

int ProcessTransaction(int balance, int amount, int txType) {
    int result;
    result = balance;
    if (txType == 1) {
        result = balance + amount;
    }
    else if (txType == 2 && balance >= amount) {
        result = balance - amount;
    }
    return result;
}

int CalculateInterest(int principal, int rate, int years) {
    int amount;
    int i;
    int interest;
    amount = principal;
    for (i = 0; i < years; i++) {
        interest = amount * rate / 100;
        amount = amount + interest;
    }
    return amount;
}

